"
PREFIX sh: <http://www.w3.org/ns/shacl#>    
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

CONSTRUCT {
    ?validationResult a sh:ValidationResult ;
        sh:resultSeverity %s ;
        sh:sourceShape %s ;
        sh:sourceConstraintComponent ?sourceConstraintComponent ;
        sh:focusNode ?focusNode ;
        sh:value ?value ;
        %s
        sh:resultMessage ?resultMessage .   
}
WHERE {
    %s
}
    "

"
    {
        %s
        BIND(?focusNode AS ?x)

        FILTER NOT EXISTS { ?x %s [] }

        BIND(BNODE() AS ?validationResult)
        BIND(sh:MinCountConstraintComponent AS ?sourceConstraintComponent)
        BIND(%s AS ?resultMessage)
    }
    "

"
    {
        SELECT ?focusNode ?value # sh:MinCountConstraintComponent
        WHERE {
            %s
            %s
            %s
            FILTER NOT EXISTS { ?x %s [] }
        }
    }
    "

"
    {
        %s
        BIND(?focusNode AS ?x)

        {
            SELECT ?x (COUNT(?value) AS ?count)
            WHERE { ?x %s ?value } 
            GROUP BY ?x
            HAVING (COUNT(?value) < %s)
        }

        BIND(BNODE() AS ?validationResult)
        BIND(sh:MinCountConstraintComponent AS ?sourceConstraintComponent)
        BIND(%s AS ?resultMessage)
    }
    "

"
    {
        SELECT ?focusNode ?value # sh:MinCountConstraintComponent
        WHERE {
            %s
            %s
            %s
            {
                SELECT ?x
                WHERE { ?x %s ?value } 
                GROUP BY ?x
                HAVING (COUNT(?value) < %s)
            }
        }
    }
    "

"
    {
        %s
        BIND(?focusNode AS ?x)

        {
            SELECT ?x (COUNT(?value) AS ?count)
            WHERE { ?x %s ?value } 
            GROUP BY ?x
            HAVING (COUNT(?value) > %s)
        }

        BIND(BNODE() AS ?validationResult)
        BIND(sh:MaxCountConstraintComponent AS ?sourceConstraintComponent)
        BIND(%s AS ?resultMessage)
    }
    "

"
    {
        SELECT ?focusNode ?value # MaxCountConstraintComponent
        WHERE {
            %s
            %s
            %s
            {
                SELECT ?x
                WHERE { ?x %s ?value } 
                GROUP BY ?x
                HAVING (COUNT(?value) > %s)
            }
        }
    }
    "

"
    {
        %s
        BIND(?focusNode AS ?x)

        {
            SELECT ?x ?lang (COUNT(?lang) AS ?count)
            WHERE { 
                ?x %s ?o 
                BIND(lang(?o) AS ?lang)
                FILTER(?lang != "")
            } 
            GROUP BY ?x ?lang
            HAVING (COUNT(?lang) > 1)
        }

        BIND(BNODE() AS ?validationResult)
        BIND(sh:UniqueLangConstraintComponent AS ?sourceConstraintComponent)
        BIND(%s AS ?resultMessage)
    }
    "

"
    {
        SELECT ?focusNode ?value # UniqueLangConstraintComponent
        WHERE {
            %s
            %s
            %s
            {
                SELECT ?x
                WHERE { 
                    ?x %s ?o 
                    BIND(lang(?o) AS ?lang)
                    FILTER(?lang != "")
                } 
                GROUP BY ?x ?lang
                HAVING (COUNT(?lang) > 1)
            }
        }
    }
    "

"
    {
        %s
        BIND(?focusNode AS ?x)

        {
            { ?x %s ?value } MINUS { ?x %s ?value }
        }
        UNION
        {
            { ?x %s ?value } MINUS { ?x %s ?value } 
        }

        BIND(BNODE() AS ?validationResult)
        BIND(sh:EqualsConstraintComponent AS ?sourceConstraintComponent)
        BIND(%s AS ?resultMessage)
    }
    "

"
    {
        SELECT ?focusNode ?value # EqualsConstraintComponent
        WHERE {
            %s
            %s
            %s
            {
                {
                    { ?x %s ?o } MINUS { ?x %s ?o }
                }
                UNION
                {
                    { ?x %s ?o } MINUS { ?x %s ?o } 
                }
            }
        }
    }
    "

"
    {
        {
            %s
            { ?focusNode %s ?value . FILTER (?value != ?focusNode) }
        }
        UNION
        {
            %s
            BIND(?focusNode AS ?value)
            FILTER NOT EXISTS { ?focusNode %s ?value . }
        }

        BIND(BNODE() AS ?validationResult)
        BIND(sh:EqualsConstraintComponent AS ?sourceConstraintComponent)
        BIND(%s AS ?resultMessage)
    }
    "

"
    {
        SELECT ?focusNode ?value # EqualsConstraintComponent for NodeShape
        WHERE {
            {
                { 
                    %s
                    %s
                    %s
                    ?x %s ?o . FILTER (?o != ?x)     
                }
                UNION
                {
                    %s
                    %s
                    %s
                    FILTER NOT EXISTS { ?x %s ?x }
                }
            }
        }
    }
    "

"
    {
        %s
        {
            SELECT ?focusNode ?value ?otherValue WHERE {
                ?focusNode %s ?value . 
                ?focusNode %s ?otherValue .
                FILTER NOT EXISTS {
                    FILTER(?value < ?otherValue)
                }
            }
        }
        BIND(BNODE() AS ?validationResult)
        BIND(sh:LessThanConstraintComponent AS ?sourceConstraintComponent)
        BIND(%s AS ?resultMessage)
    }
    "

"
    {
        SELECT ?focusNode ?value # LessThanConstraintComponent
        WHERE {
            %s
            %s
            %s

            ?x %s ?o1 . 
            ?x %s ?o2 .
            FILTER NOT EXISTS {
                FILTER(?o1 < ?o2)
            }
        }
    }
    "

"
    {
        %s
        {
            SELECT ?focusNode ?value ?otherValue WHERE {
                ?focusNode %s ?value . 
                ?focusNode %s ?otherValue .
                FILTER NOT EXISTS {
                    FILTER(?value <= ?otherValue)
                }
            }
        }
        BIND(BNODE() AS ?validationResult)
        BIND(sh:LessThanOrEqualsConstraintComponent AS ?sourceConstraintComponent)
        BIND(%s AS ?resultMessage)
    }
    "

"
    {
        SELECT ?focusNode ?value # LessThanOrEqualsConstraintComponent
        WHERE {
            %s
            %s
            %s

            ?x %s ?o1 . 
            ?x %s ?o2 .
            FILTER NOT EXISTS {
                FILTER(?o1 <= ?o2)
            }
        }
    }
    "

"
    {
        %s
        %s

        {
            SELECT DISTINCT ?focusNode ?value WHERE 
            {
                %s
            }
        }

        BIND(BNODE() AS ?validationResult)
        BIND(sh:OrConstraintComponent AS ?sourceConstraintComponent)
        BIND(%s AS ?resultMessage)
    }
    "

"
    {
        {
            %s
            %s
        }
        MINUS
        {
            %s
        }

        BIND(BNODE() AS ?validationResult)
        BIND(sh:NotConstraintComponent AS ?sourceConstraintComponent)
        BIND(%s AS ?resultMessage)
    }
    "

"
    {
        %s
        %s

        {
            SELECT DISTINCT ?focusNode ?value WHERE 
            {
                %s
            }
        }


        BIND(BNODE() AS ?validationResult)
        BIND(sh:AndConstraintComponent AS ?sourceConstraintComponent)
        BIND(%s AS ?resultMessage)
    }
    "

"
    {
        {
            SELECT ?focusNode ?value (COUNT(?shape) AS ?count)
            WHERE {
            {
                %s
                %s
            }
            UNION
            {
                %s
            }
            }
            GROUP BY ?focusNode ?value
            HAVING (COUNT(?shape) != 1)   
        }
        BIND(BNODE() AS ?validationResult)
        BIND(sh:XoneConstraintComponent AS ?sourceConstraintComponent)
        BIND(%s AS ?resultMessage)
    }
    "

"
    {
        SELECT ?focusNode ?value
        WHERE {
        {
            %s
            %s
        }
        UNION
        {
            %s
        }
        }
        GROUP BY ?focusNode ?value
        HAVING (COUNT(?shape) != 1)   

    }
    "

"
    {
        { 
            SELECT DISTINCT ?focusNode ?value 
            WHERE 
            {
                %s
            }
        }
        BIND(BNODE() AS ?validationResult)
        BIND(sh:NodeConstraintComponent AS ?sourceConstraintComponent)
        BIND(%s AS ?resultMessage)
    }
    "

"
    {
        %s
        FILTER NOT EXISTS { 
            %s
            %s
            MINUS {
                %s
            }
        }

        BIND(BNODE() AS ?validationResult)
        BIND(sh:QualifiedMinCountConstraintComponent AS ?sourceConstraintComponent)
    }
    "

"
    {
        { 
            SELECT ?focusNode
            WHERE {
                %s
                %s
            MINUS
                %s
            }
            GROUP BY ?focusNode
            HAVING (COUNT(?value) < %s)

        }
        BIND(BNODE() AS ?validationResult)
        BIND(sh:QualifiedMinCountConstraintComponent AS ?sourceConstraintComponent)
    }
    "

"
    {
        { 
            SELECT ?focusNode
            WHERE {
                %s
                %s
            MINUS
                %s
            }
            GROUP BY ?focusNode
            HAVING (COUNT(?value) > %s)

        }
        BIND(BNODE() AS ?validationResult)
        BIND(sh:QualifiedMaxCountConstraintComponent AS ?sourceConstraintComponent)
    }
    "

"
    {
        %s
        BIND(?focusNode AS ?x)

        FILTER NOT EXISTS { ?x %s %s}

        BIND(BNODE() AS ?validationResult)
        BIND(sh:HasValueConstraintComponent AS ?sourceConstraintComponent)
        BIND(%s AS ?resultMessage)
    }
    "
